class Solution {
    public int minMovesToMakePalindrome(String s) {
        int n = s.length();
        char[] arr = s.toCharArray();
        int res = 0;
        int left = 0, right = n - 1;
        while (left < right) {
            if (arr[left] == arr[right]) {
                left++;
                right--;
            } else {
                int tempLeft = left + 1;
                while (tempLeft < right && arr[tempLeft] != arr[right]) {
                    tempLeft++;
                }
                if (tempLeft < right) {
                    res += tempLeft - left;
                    for (int i = tempLeft; i > left; i--) {
                        char temp = arr[i];
                        arr[i] = arr[i - 1];
                        arr[i - 1] = temp;
                    }
                    left++;
                    right--;
                } else {
                    res += right - left;
                    for (int i = right; i < left; i++) {
                        char temp = arr[i];
                        arr[i] = arr[i + 1];
                        arr[i + 1] = temp;
                    }
                    left++;
                    right--;
                }
            }
        }
        return res;
    }
}
